/* ISTQB Glossary - Foundation level (239 terms)
   en/ru = term (EN / RU), de = official EN definition (verbatim),
   dr = RU definition, o = 1 if RU is official ISTQB text, 0 if our translation.
   Source: https://glossary.istqb.org  (EN verbatim; RU pulled per-term from ru_RU locale). */

window.TERMS = [
{en:"acceptance criteria",ru:"критерии приёмки",t:"process",o:1,de:"The criteria that a work product must satisfy to be accepted by the stakeholders.",dr:"Критерии, которым должен удовлетворять продукт, чтобы быть принятым заинтересованными сторонами."},
{en:"acceptance test-driven development",ru:"разработка через приемочное тестирование",t:"agile",o:1,de:"A collaboration-based test-first approach that defines acceptance tests in the stakeholders' domain language.",dr:"Подход опережающего проектирования тестов, основанный на совместной работе, который определяет приемочные тесты на языке предметной области заинтересованных сторон"},
{en:"acceptance testing",ru:"приёмочное тестирование",t:"levels",o:1,de:"A test level that focuses on determining whether to accept the system.",dr:"Уровень тестирования, целью которого является определение того, принимать ли систему"},
{en:"actual result",ru:"фактический результат",t:"process",o:1,de:"The behavior produced/observed when a component or system is tested.",dr:"Наблюдаемое или генерируемое поведение компонента или системы во время тестирования."},
{en:"Agile Manifesto",ru:"манифест гибкой методологии",t:"agile",o:1,de:"A statement on the values that underpin Agile software development. The values are: individuals and interactions over processes and tools, working software over comprehensive documentation, customer collaboration over contract negotiation, responding to change over following a plan.",dr:"Заявления о ценностях, которые подкрепляют гибкую методологию разработки. Этими ценностями являются: личности и взаимодействия важнее, чем процессы и инструменты, работающее программное обеспечение важнее, чем полная документация, сотрудничество с заказчиком важнее, чем контрактные обязательства, реакция на изменения важнее, чем следование плану."},
{en:"Agile software development",ru:"гибкая методология разработки программного обеспечения",t:"agile",o:1,de:"A group of software development lifecycle models based on iterative incremental development, where requirements and solutions evolve through collaboration between self-organizing cross-functional teams.",dr:"Группа методологий разработки программного обеспечения, основанных на итеративной поэтапной разработке, где требования и решения развиваются посредством сотрудничества между самоорганизующимися межфункциональными командами."},
{en:"alpha testing",ru:"альфа-тестирование",t:"levels",o:1,de:"A type of acceptance testing performed in the developer's test environment by roles outside the development organization.",dr:"Тип приемочного тестирования, которое проводится потенциальными пользователями/заказчиками или независимой командой тестирования на стороне разработчиков, но вне разрабатывающей организации."},
{en:"anomaly",ru:"аномалия",t:"defect",o:1,de:"A condition that deviates from expectation.",dr:"Любое состояние, отличающееся от ожидаемого"},
{en:"API testing",ru:"тестирование с помощью API",t:"types",o:1,de:"A test approach performed by submitting requests to a test object using its application programming interface.",dr:"Подход к тестированию, выполняемый путем отправки команд непосредственно к объекту тестирования, используя программные интерфейсы приложения"},
{en:"appropriateness recognizability",ru:"определимость пригодности",t:"quality",o:1,de:"The degree to which users can recognize whether a component or system is appropriate for their needs.",dr:"Степень соответствия компонента или системы потребностям пользователя."},
{en:"audit",ru:"аудит",t:"static",o:1,de:"An independent examination performed by a third party on a work product or process to assess whether it complies with specified criteria.",dr:"Независимый анализ рабочего продукта или процесса, выполняемый третьей стороной с целью оценки его соответствия установленным критериям."},
{en:"availability",ru:"доступность",t:"quality",o:1,de:"The degree to which a component or system is operational and accessible when required for use.",dr:"Уровень готовности и доступности компонента или системы при необходимости их использования."},
{en:"behavior-driven development",ru:"разработка на основе поведения",t:"agile",o:1,de:"A collaborative approach to development in which the team is focusing on delivering expected behavior of a component or system for the customer, which forms the basis for testing.",dr:"Подход к совместной разработке, при котором команда фокусируется на достижении ожидаемого поведения компонента или системы для заказчика, формируя таким образом базис тестирования"},
{en:"beta testing",ru:"бета-тестирование",t:"levels",o:1,de:"A type of acceptance testing performed at an external site to the developer's test environment by roles outside the development organization.",dr:"Тип приемочного тестирования, которое проводится третьей стороной, не относящейся к организации-разработчику."},
{en:"black-box test technique",ru:"тестирование методом черного ящика",t:"tech",o:1,de:"A test technique based on the specification of a component or system.",dr:"Методика тестирования, основанная на анализе спецификации компонента или системы."},
{en:"black-box testing",ru:"тестирование чёрного ящика",t:"types",o:0,de:"A test approach based on the specification of a component or system.",dr:"Подход к тестированию, основанный на спецификации компонента или системы."},
{en:"boundary value",ru:"граничное значение",t:"tech",o:1,de:"A minimum or maximum value of an ordered equivalence partition.",dr:"Минимальное или максимальное значение, принадлежащее упорядоченной эквивалентной области."},
{en:"boundary value analysis",ru:"анализ граничных значений",t:"tech",o:0,de:"A black-box test technique in which the test conditions are boundary values.",dr:"Техника тестирования чёрного ящика, в которой условиями тестирования являются граничные значения."},
{en:"branch",ru:"ветвь",t:"tech",o:1,de:"A transfer of control between two consecutive nodes in the control flow graph of a test item.",dr:"Передача управления между двумя последовательными узлами графа потока управления тестируемого элемента"},
{en:"branch coverage",ru:"покрытие ветвей",t:"tech",o:1,de:"The coverage of branches in a control flow graph.",dr:"Обеспечение тестового покрытия ветвей в графе потока управления"},
{en:"branch testing",ru:"тестирование ветвей",t:"tech",o:1,de:"A white-box test technique in which the test conditions are branches.",dr:"Техника тестирования методом белого ящика, в которой тестовые условия представлены ветвями."},
{en:"build verification test",ru:"тест верификации сборки",t:"auto",o:1,de:"An automated test that validates the integrity of each new build and verifies its key/core functionality, stability, and testability.",dr:"Набор автоматических тестов, валидирующих целостность каждой новой сборки и верифицирующих ее ключевую/базовую функциональность, стабильность и тестируемость."},
{en:"cause-effect diagram",ru:"причинно-следственная диаграмма",t:"defect",o:1,de:"A graphical representation used to organize and display the interrelationships of various possible root causes of a problem. Possible causes of a real or potential defect or failure are organized in categories and subcategories in a horizontal tree-structure, with the (potential) defect or failure as the root node.",dr:"Графическое представление, используемое для организации и отображения взаимосвязей различных возможных первопричин проблемы. Возможные причины возникновения реального или потенциального дефекта или отказа организованы в категории и подкатегории в древовидную структуру, с (потенциальным) дефектом или отказом в качестве корневого узла."},
{en:"checklist-based reviewing",ru:"рецензирование на основе чек-листов",t:"static",o:1,de:"A review technique guided by a list of questions or required attributes.",dr:"Техника рецензирования, основанная на перечне вопросов или требуемых атрибутов."},
{en:"checklist-based testing",ru:"тестирование на основе чек-листов",t:"tech",o:1,de:"An experience-based test technique in which test cases are designed to exercise the items of a checklist.",dr:"Техника тестирования на основе опыта, при которой тестовые сценарии разрабатываются для выполнения пунктов чек-листа."},
{en:"coding standard",ru:"стандарт оформления кода",t:"static",o:1,de:"A quality standard that defines required characteristics of code.",dr:"Стандарт качества, описывающий требуемые характеристики исходного кода"},
{en:"collaboration-based test approach",ru:"подход к тестированию на основе совместной работы",t:"agile",o:1,de:"An approach to testing that focuses on defect avoidance by collaborating among stakeholders.",dr:"Подход к тестированию, основанный на сотрудничестве между заинтересованными сторонами для предотвращения дефектов."},
{en:"compatibility",ru:"совместимость",t:"quality",o:1,de:"The degree to which a component or system can exchange information with other components or systems, and/or perform its required functions while sharing the same hardware or software environment.",dr:"Степень, с которой компонент или система могут обмениваться информацией с другими компонентами или системами и/или выполнять свои требуемые функции, используя одну и ту же аппаратную или программную среду."},
{en:"compliance",ru:"соответствие",t:"quality",o:1,de:"Adherence of a work product to standards, conventions or regulations in laws and similar prescriptions.",dr:"Соответствие рабочего продукта стандартам, соглашениям или правилам законодательства, а также другим аналогичным требованиям."},
{en:"component",ru:"компонент",t:"levels",o:1,de:"A part of a system that can be tested in isolation.",dr:"Часть системы, которая может быть протестирована отдельно."},
{en:"component integration testing",ru:"интеграционное тестирование компонентов",t:"levels",o:1,de:"The integration testing of components.",dr:"Тестирование интеграции компонентов"},
{en:"component testing",ru:"компонентное тестирование",t:"levels",o:1,de:"A test level that focuses on individual hardware or software components.",dr:"Уровень тестирования отдельных аппаратных или программных компонентов системы."},
{en:"confirmation testing",ru:"подтверждающее тестирование",t:"types",o:1,de:"A type of change-related testing performed after fixing a defect to confirm that a failure caused by that defect does not reoccur.",dr:"Тип тестирования, связанного с изменениями, которое выполняется после исправления дефекта для подтверждения того, что отказ, вызванный этим дефектом, не воспроизводится."},
{en:"continuous delivery",ru:"непрерывный процесс поставки",t:"agile",o:1,de:"An automated software development procedure in which code changes are automatically built, tested, and prepared for a release to production.",dr:"Автоматизированная процедура разработки программного обеспечения, при которой изменения в коде автоматически создаются, тестируются и подготавливаются к выпуску в эксплуатационную среду."},
{en:"continuous deployment",ru:"непрерывный процесс внедрения",t:"agile",o:1,de:"An automated software release procedure in which all code changes are deployed to production after all specified tests have passed.",dr:"Автоматизированная процедура выпуска программного обеспечения, при которой все изменения в коде внедряются в эксплуатационную среду после прохождения всех требуемых тестов."},
{en:"continuous integration",ru:"непрерывная интеграция",t:"agile",o:1,de:"An automated software development procedure that merges, integrates and tests all changes as soon as they are committed.",dr:"Автоматизированная процедура разработки программного обеспечения, которая объединяет, интегрирует и тестирует все изменения, как только они вносятся."},
{en:"continuous testing",ru:"непрерывное тестирование",t:"agile",o:0,de:"A test approach that performs testing throughout the software development lifecycle, early and often, and automates tests to obtain feedback as quickly as possible on software release candidates.",dr:"Подход к тестированию, при котором тестирование выполняется на протяжении всего жизненного цикла разработки — рано и часто — с автоматизацией тестов для максимально быстрой обратной связи по кандидатам на выпуск."},
{en:"control flow",ru:"поток управления",t:"tech",o:1,de:"The sequence in which operations are performed by a business process, component or system.",dr:"Последовательность, в которой выполняются операции бизнес-процессом, компонентом или системой."},
{en:"cost of quality",ru:"стоимость качества",t:"mgmt",o:1,de:"The total costs incurred on quality activities and defects, often split into the costs of defect prevention, appraisal, internal failure, and external failure.",dr:"Общая стоимость затрат на задачи обеспечения и проблемы качества, часто разделяемая на стоимость предотвращения, стоимость оценки, стоимость внутренних отказов и стоимость внешних отказов."},
{en:"coverage",ru:"покрытие",t:"tech",o:1,de:"The degree to which specified coverage items are exercised by a test suite, expressed as a percentage.",dr:"Степень покрытия определенных элементов набором тестов, выражаемая в процентах"},
{en:"coverage criteria",ru:"критерии покрытия",t:"tech",o:1,de:"The criteria to define the coverage items required to reach a test objective.",dr:"Критерии для определения элементов покрытия, необходимых для достижения цели тестирования."},
{en:"coverage item",ru:"элемент покрытия",t:"tech",o:1,de:"An attribute or combination of attributes derived from one or more test conditions by using a test technique.",dr:"Атрибут или комбинация атрибутов, полученные из одного или более тестовых условий с помощью одной из методик тестирования и позволяющие измерить тщательность исполнения теста"},
{en:"dashboard",ru:"сводная таблица",t:"mgmt",o:1,de:"A representation of dynamic measurements of operational performance for some organization or activity, using metrics represented via metaphors such as visual dials, counters, and other devices resembling those on the dashboard of an automobile, so that the effects of events or activities can be easily understood and related to operational goals.",dr:"Представление динамических измерений операционной производительности организации или активности, используя метрики, в виде метафор, например, циферблата или счетчиков, и других механизмов, похожих на приборную доску автомобиля, так, чтобы события или действия могли быть легко поняты и связаны с операционными целями."},
{en:"debugging",ru:"отладка",t:"fund",o:1,de:"The process of finding, analyzing and removing the causes of failures in a component or system.",dr:"Процесс поиска, анализа, и устранения причин отказов в компоненте или системе"},
{en:"decision coverage",ru:"покрытие решений",t:"tech",o:1,de:"The coverage of decision outcomes.",dr:"Покрытие результатов решений."},
{en:"decision table testing",ru:"тестирование с помощью таблицы решений",t:"tech",o:1,de:"A black-box test technique in which the test conditions are the combinations of conditions and the resulting actions shown in a decision table.",dr:"Тестирование методом черного ящика, в котором тестовые условия представляют собой комбинации условий и результирующих действий, отраженных в таблице решений."},
{en:"defect",ru:"дефект",t:"defect",o:1,de:"An imperfection or deficiency in a work product where it does not meet its requirements or specifications or impairs its intended use.",dr:"Недостаток рабочего продукта, проявляющийся в несоответствии требованиям или спецификациям и ухудшающий целевое использование этого продукта."},
{en:"defect density",ru:"плотность дефектов",t:"defect",o:1,de:"The number of defects per unit size of a work product.",dr:"Количество дефектов на единицу размера рабочего продукта"},
{en:"defect detection percentage",ru:"процент выявления дефектов",t:"defect",o:1,de:"The number of defects found by a test level, divided by the number found by that test level and any other means afterwards.",dr:"Количество дефектов, выявленных во время фазы тестирования, деленное на число дефектов, найденных во время этой фазы тестирования, а также во время всех последующих фазах."},
{en:"defect management",ru:"управление дефектами",t:"defect",o:1,de:"The process of recognizing, recording, classifying, investigating, fixing and disposing of defects.",dr:"Процесс выявления, регистрации, классификации, исследования, исправления и устранения дефектов в программном обеспечении."},
{en:"defect report",ru:"отчет о дефекте",t:"defect",o:1,de:"Documentation of the occurrence, nature, and status of a defect.",dr:"Документирование возникновения, характера и состояния дефекта"},
{en:"defect taxonomy",ru:"классификация дефектов",t:"defect",o:1,de:"A list of categories designed to identify and classify defects.",dr:"Список категорий, разработанный для идентификации и классификации дефектов"},
{en:"defect-based test technique",ru:"методика создания сценариев тестирования на основе дефектов",t:"tech",o:1,de:"A test technique in which test conditions are based on a specific defect type.",dr:"Метод тестирования, в котором сценарии тестирования проектируются на основе известных типов дефектов."},
{en:"driver",ru:"драйвер",t:"auto",o:1,de:"A component or tool that temporarily replaces another component and controls or calls a test item in isolation.",dr:"Компонент или инструмент тестирования, который заменяет другой компонент, обеспечивающий изолированное управление или вызов тестируемого элемента"},
{en:"dynamic testing",ru:"динамическое тестирование",t:"fund",o:1,de:"A test approach that involves test execution of a test item.",dr:"Тестирование, проводимое во время выполнения тестируемого элемента"},
{en:"each choice coverage",ru:"покрытие каждого выбора",t:"tech",o:0,de:"The coverage of equivalence partitions in multiple sets of partitions.",dr:"Покрытие классов эквивалентности в нескольких наборах разбиений."},
{en:"effectiveness",ru:"результативность",t:"quality",o:1,de:"The extent to which correct and complete goals are achieved.",dr:"Степень достижения правильных завершенных целей."},
{en:"efficiency",ru:"эффективность",t:"quality",o:1,de:"The degree to which resources are expended in relation to results achieved.",dr:"Отношение затраченных ресурсов к достигнутым целям пользователей."},
{en:"entry criteria",ru:"критерии входа",t:"mgmt",o:1,de:"The set of conditions for officially starting a defined task.",dr:"Набор условий, необходимых для официального старта определенной задачи"},
{en:"equivalence partition",ru:"класс эквивалентности",t:"tech",o:0,de:"A subset of a value domain for which a component or system is expected to treat all values the same based on the specification.",dr:"Подмножество области значений, для которого ожидается, что компонент или система обрабатывает все значения одинаково согласно спецификации."},
{en:"equivalence partitioning",ru:"эквивалентное разбиение",t:"tech",o:1,de:"A black-box test technique in which test conditions are equivalence partitions exercised by one representative member of each partition.",dr:"Разработка тестов методом черного ящика, при которой тестовые условия представлены эквивалентными областями, проверяемыми на одном представителе каждой области"},
{en:"error",ru:"ошибка",t:"defect",o:1,de:"A human action that results in a defect.",dr:"Действие человека, которое приводит к возникновению дефекта"},
{en:"error guessing",ru:"предугадывание ошибок",t:"tech",o:0,de:"A test technique in which the tests conditions are based on the tester's knowledge of past failures or failure modes.",dr:"Техника тестирования, в которой условия тестирования основаны на знании тестировщиком прошлых отказов или режимов отказа."},
{en:"exhaustive testing",ru:"исчерпывающее тестирование",t:"fund",o:1,de:"A test approach in which the test suite comprises all combinations of input values and preconditions.",dr:"Методика тестирования, в которой набор тестов включает в себя все комбинации входных данных и предусловий."},
{en:"exit criteria",ru:"критерии выхода",t:"mgmt",o:1,de:"The set of conditions for officially completing a defined task.",dr:"Набор условий, необходимых для официального завершения определенной задачи"},
{en:"expected result",ru:"ожидаемый результат",t:"process",o:1,de:"The observable predicted behavior of a test item under specified conditions based on its test basis.",dr:"Прогнозируемое наблюдаемое поведение компонента или системы при конкретных условиях, основанных на спецификации или другом источнике"},
{en:"experience-based test technique",ru:"методика тестирования на основе опыта",t:"tech",o:1,de:"A test technique based on the tester's experience, knowledge and intuition.",dr:"Методика тестирования, основанная на опыте, знаниях и интуиции тестировщика"},
{en:"experience-based testing",ru:"тестирование на основе опыта",t:"tech",o:1,de:"A test approach based on the tester's experience, knowledge and intuition.",dr:"Подход к тестированию, основанный на опыте, знаниях и интуиции тестировщика."},
{en:"exploratory testing",ru:"исследовательское тестирование",t:"tech",o:0,de:"A test approach in which tests are dynamically designed and executed based on tester's knowledge, exploration of a test item, and previous test results.",dr:"Подход к тестированию, при котором тесты динамически проектируются и выполняются на основе знаний тестировщика, исследования объекта и предыдущих результатов тестов."},
{en:"failed",ru:"тест не пройден",t:"process",o:1,de:"A test result if the actual result does not match the expected result.",dr:"Статус результата теста, при котором фактический результат не соответствует ожидаемому результату"},
{en:"failure",ru:"отказ",t:"defect",o:1,de:"An event in which a component or system does not meet its requirements within specified limits during its execution.",dr:"Событие, при котором компонент или система не удовлетворяют требованиям в установленных пределах во время своего выполнения."},
{en:"fault attack",ru:"атака на дефекты",t:"tech",o:1,de:"A test technique to evaluate a specific quality characteristic of a test object by attempting to trigger specific failures.",dr:"Метод тестирования для оценки конкретной характеристики качества объекта тестирования путем попытки вызвать определенные сбои."},
{en:"feature-driven development",ru:"разработка на основе функционала",t:"agile",o:1,de:"An iterative and incremental software development process driven from a client-valued functionality (feature) perspective. Feature-driven development is mostly used in Agile software development.",dr:"Итеративный и инкрементальный процесс разработки на основе функциональности, определяемой и приоретизируемой клиентом. Разработка на основе функционала в основном используется в гибких методологиях разработки."},
{en:"finding",ru:"находка",t:"defect",o:1,de:"A result of an evaluation that identifies some important issue, problem, or opportunity.",dr:"Результат анализа, который выявляет какую-то важную задачу, проблему или возможность."},
{en:"formal review",ru:"формальное рецензирование",t:"static",o:1,de:"A review that follows a defined process with a formally documented output.",dr:"Тип рецензирования, который следует строго определенному процессу с официально задокументированными результатами."},
{en:"functional appropriateness",ru:"функциональная приемлемость",t:"quality",o:1,de:"The degree to which the functions facilitate the accomplishment of specified tasks and objectives.",dr:"Степень, с которой функции облегчают достижение конкретных задач и целей."},
{en:"functional completeness",ru:"функциональная полнота",t:"quality",o:1,de:"The degree to which the set of functions covers all the specified tasks and user objectives.",dr:"Степень, с которой набор функций покрывает все указанные задачи и цели пользователя."},
{en:"functional correctness",ru:"функциональная корректность",t:"quality",o:1,de:"The degree to which a component or system provides the correct results with the needed degree of precision.",dr:"Степень, с которой компонент или система обеспечивает правильные результаты с требуемой точностью."},
{en:"functional suitability",ru:"функциональная пригодность",t:"quality",o:1,de:"The degree to which a component or system provides functions that meet stated and implied needs when used under specified conditions.",dr:"Степень, с которой функции компонента или системы удовлетворяют заявленным требованиям при использовании в определенных условиях."},
{en:"functional testing",ru:"функциональное тестирование",t:"types",o:0,de:"A test type to determine the functional suitability of a test object.",dr:"Тип тестирования для определения функциональной пригодности объекта тестирования."},
{en:"heuristic",ru:"эвристика",t:"tech",o:1,de:"A generally recognized rule of thumb that helps to achieve a goal.",dr:"Эмпирическое правило, которое помогает достичь цели."},
{en:"impact analysis",ru:"анализ влияния",t:"mgmt",o:1,de:"The identification of all work products affected by a change, including an estimate of the resources needed to accomplish the change.",dr:"Определение всех объектов, подверженных влиянию изменения, а также оценка ресурсов, необходимых для реализации изменения"},
{en:"incremental development model",ru:"инкрементная модель разработки",t:"agile",o:1,de:"A type of software development lifecycle model in which the component or system is developed through a series of increments.",dr:"Тип модели жизненного цикла разработки, в которой компонент или система разрабатываются посредством серии приращений функциональности."},
{en:"independence of testing",ru:"независимость тестирования",t:"fund",o:1,de:"Separation of responsibilities, which encourages the accomplishment of objective testing.",dr:"Разделение ответственностей, которое позволяет выполнять объективное тестирование."},
{en:"informal review",ru:"неформальное рецензирование",t:"static",o:1,de:"A type of review that does not follow a defined process and has no formally documented output.",dr:"Рецензирование, которое не основано на формальной (документированной) процедуре"},
{en:"inspection",ru:"инспекция",t:"static",o:1,de:"A type of formal review that uses defined team roles and measurement to identify defects in a work product, and improve the review process and the software development process.",dr:"Тип формального рецензирования, при котором используются определенные роли и метрики, чтобы выявлять дефекты в рабочем продукте и улучшить как процесс рецензирования, так и процесс разработки программного обеспечения."},
{en:"integration testing",ru:"интеграционное тестирование",t:"levels",o:1,de:"A test level that focuses on interactions between components or systems.",dr:"Уровень тестирования, который фокусируется на взаимодействии между компонентами или системами"},
{en:"integrity",ru:"целостность",t:"quality",o:1,de:"The degree to which only authorized access and modification is allowed to a component, a system or data.",dr:"Степень, с которой к компоненту, системе или данным разрешен только санкционированный доступ и их модификация."},
{en:"interoperability",ru:"возможность взаимодействия",t:"quality",o:1,de:"The degree to which two or more components or systems can exchange information and use the information that has been exchanged.",dr:"Характеристика, показывающая степень, с которой два и более компонента или системы могут обмениваться информацией и использовать информацию, которой обменивались"},
{en:"iterative development model",ru:"итеративная модель разработки",t:"agile",o:1,de:"A type of software development lifecycle model in which the component or system is developed through a series of repeated cycles.",dr:"Тип модели жизненного цикла разработки программного обеспечения, в которой компонент или система разрабатывается через серию повторяющихся циклов."},
{en:"maintainability",ru:"сопровождаемость",t:"quality",o:1,de:"The degree to which a component or system can be modified by the intended maintainers.",dr:"Степень того, насколько компонент или система могут быть изменены специалистами по сопровождению."},
{en:"maintenance",ru:"сопровождение",t:"process",o:1,de:"The process of modifying a component or system after delivery to correct defects, improve quality characteristics, or adapt to a changed environment.",dr:"Процесс модификации компонента или системы после поставки для исправления дефектов, повышения характеристик качества или адаптации к изменившемуся окружению"},
{en:"maintenance testing",ru:"тестирование в период сопровождения",t:"types",o:1,de:"A test type that evaluates the effect of changes made to an operational system or its environment.",dr:"Тестирование изменений в действующей системе или влияния изменений в окружении на действующую систему."},
{en:"maturity",ru:"зрелость",t:"quality",o:1,de:"(1) The capability of an organization with respect to the effectiveness and efficiency of its processes and work practices. (2) The degree to which a component or system meets needs for reliability under normal operation.",dr:"1. Уровень эффективности корпоративных процессов и методик конкретной организации. 2. Степень соответствия компонента или системы требованиям надежности при нормальной эксплуатации."},
{en:"mean time to failure",ru:"среднее время до отказа",t:"quality",o:1,de:"The average time from the start of operation to a failure for a component or system.",dr:"Среднее время от начала работы до отказа компонента или системы."},
{en:"measurement",ru:"измерение",t:"mgmt",o:1,de:"The process of assigning a number or category to an entity to describe an attribute of that entity.",dr:"Процесс присвоения числа или категории сущности для описания атрибута этой сущности."},
{en:"metric",ru:"метрика",t:"mgmt",o:1,de:"A measurement scale and the method used for measurement.",dr:"Шкала измерений и метод, используемый для измерений."},
{en:"model-based testing",ru:"тестирование на основе модели",t:"tech",o:1,de:"Testing based on or involving models.",dr:"Тестирование на основе моделей или с их участием."},
{en:"moderator",ru:"координатор",t:"static",o:1,de:"(1) The person responsible for running review meetings. (2) The person who performs a usability test session.",dr:"1. Лицо, ответственное за проведение собраний, посвященных рецензированию. 2. Лицо, которое координирует сессию тестирования практичности."},
{en:"N-switch coverage",ru:"покрытие N-переходов",t:"tech",o:1,de:"The coverage of sequences of N+1 transitions.",dr:"Покрытие последовательностей из N+1 переходов."},
{en:"negative testing",ru:"негативное тестирование",t:"types",o:1,de:"A test type in which a component or system is used in a way that it is not intended.",dr:"Тип тестирования, при котором компонент или система используются не так, как запланировано"},
{en:"non-functional testing",ru:"нефункциональное тестирование",t:"types",o:1,de:"A test type to evaluate that a component or system complies with non-functional requirements.",dr:"Тестирование, выполняемое для оценки соответствия компонента или системы нефункциональным требованиям"},
{en:"operational acceptance testing",ru:"эксплуатационное приёмочное тестирование",t:"levels",o:0,de:"A type of acceptance testing performed to determine whether the organization responsible for operating the system can accept it.",dr:"Вид приёмочного тестирования для определения, может ли организация, ответственная за эксплуатацию системы, принять её."},
{en:"pair testing",ru:"парное тестирование",t:"tech",o:1,de:"A test approach in which two team members simultaneously collaborate on testing a work product.",dr:"Подход к тестированию, при котором два участника команды одновременно выполняют тестирование рабочего продукта"},
{en:"passed",ru:"пройден",t:"process",o:1,de:"A test result if the actual result matches the expected result.",dr:"Статус результата теста, при котором фактический результат соответствует ожидаемому результату"},
{en:"performance efficiency",ru:"эффективность производительности",t:"quality",o:1,de:"The degree to which a component or system uses time, resources, and capacity to perform its functions under specified conditions.",dr:"Уровень использования компонентом или системой времени, ресурсов и мощности при выполнении назначенных функций."},
{en:"planning poker",ru:"покер планирования",t:"agile",o:1,de:"A consensus-based estimation technique, mostly used to estimate effort or relative size of user stories in Agile software development. It is a variation of the Wideband Delphi method using a deck of cards with values representing the units in which the team estimates.",dr:"Метод оценки трудозатрат, основанный на всеобщем одобрении. Обычно используется для оценки затрат или относительного объема пользовательских историй в гибких методологиях разработки программного обеспечения. Является вариантом широкополосного метода Дельфи с использованием колоды карт со значениями, представляющими число квантов, которыми оценивается работа."},
{en:"portability",ru:"переносимость",t:"quality",o:1,de:"The degree to which a component or system can be transferred from one hardware, software or other operational or usage environment to another.",dr:"Степень того, насколько компонент или система могут быть перенесены из одной аппаратной, программной или прочей операционной среды или среды использования в другую."},
{en:"postcondition",ru:"постусловие",t:"process",o:1,de:"The expected state of a test item and its test environment at the end of test execution.",dr:"Ожидаемое состояние элемента тестирования и его окружения после окончания выполнения теста."},
{en:"precondition",ru:"предусловие",t:"process",o:1,de:"The required state of a test item and its test environment prior to test execution.",dr:"Требуемое состояние элемента тестирования и его окружения до начала выполнения теста."},
{en:"priority",ru:"приоритет",t:"defect",o:1,de:"The level of importance assigned to a task according to specific criteria.",dr:"Степень важности, присваеваемая объекту. Например, дефекту."},
{en:"product risk",ru:"риск продукта",t:"risk",o:1,de:"A risk that impacts the quality of a product.",dr:"Риск, влияющий на качество продукта."},
{en:"project risk",ru:"риск проекта",t:"risk",o:1,de:"A risk that impacts project success.",dr:"Риск, который влияет на успех проекта."},
{en:"quality",ru:"качество",t:"fund",o:1,de:"The degree to which a work product satisfies stated and implied requirements.",dr:"Степень, в которой продукт или услуга удовлетворяет заявленным и подразумеваемым требованиям."},
{en:"quality assurance",ru:"обеспечение качества",t:"fund",o:1,de:"Activities focused on providing confidence that quality requirements will be fulfilled.",dr:"Активности, направленные на обеспечение уверенности в том, что требования к качеству будут выполнены"},
{en:"quality characteristic",ru:"характеристики качества программного обеспечения",t:"quality",o:1,de:"A category of quality attributes that bears on work product quality.",dr:"Категория атрибутов, которая имеет отношение к качеству рабочего продукта."},
{en:"quality control",ru:"контроль качества",t:"fund",o:1,de:"Activities designed to evaluate the quality of a component or system.",dr:"Набор действий, предназначенных для оценивания качества компонента или системы."},
{en:"quality risk",ru:"риск качества",t:"risk",o:1,de:"A product risk or a project risk impacting quality management.",dr:"Риск продукта или проекта, влияющий на управление качеством."},
{en:"reactive testing",ru:"реактивное тестирование",t:"tech",o:1,de:"A test approach that dynamically responds to the behavior of a test object and to test results being obtained.",dr:"Подход к тестированию, который динамически реагирует на поведение объекта тестирования и получаемые результаты тестирования."},
{en:"regression testing",ru:"регрессионное тестирование",t:"types",o:1,de:"A type of change-related testing to detect whether defects have been introduced or uncovered in unchanged areas of the software.",dr:"Тип тестирования, связанного с изменениями, чтобы найти привнесенные или ранее не обнаруженные дефекты в не менявшихся областях программного обеспечения."},
{en:"regulatory acceptance testing",ru:"регуляторное приемочное тестирование",t:"levels",o:1,de:"A type of acceptance testing performed to determine the compliance of a test object.",dr:"Тип приемочного тестирования, выполняемый для определения соответствия объекта тестирования требованиям, установленным регулятором"},
{en:"reliability",ru:"надежность",t:"quality",o:1,de:"The degree to which a component or system performs specified functions under specified conditions for a specified period of time.",dr:"Степень выполнения компонентом или системой конкретных функций в конкретных условиях в течение конкретного периода времени"},
{en:"requirement",ru:"требование",t:"process",o:1,de:"A provision that contains criteria to be fulfilled.",dr:"Условие, которое включает обязательные для выполнения критерии"},
{en:"requirements-based testing",ru:"тестирование на основе требований",t:"tech",o:1,de:"A black-box test technique in which test conditions are derived from atomic requirements.",dr:"Тестирование методом черного ящика, при котором тестовые условия разрабатываются на основе атомарных требований"},
{en:"retrospective",ru:"ретроспектива",t:"agile",o:1,de:"A regular event in which team members discuss results, review their practices, and identify ways to improve.",dr:"Регулярное мероприятие, в ходе которого участники команды обсуждают результаты, анализируют свой опыт и определяют пути совершенствования."},
{en:"review",ru:"рецензирование",t:"static",o:1,de:"A type of static testing in which the quality of a work product or process is evaluated by individuals.",dr:"Тип статического тестирования, в ходе которого качество продукта или процесса оценивается отдельными специалистами."},
{en:"reviewer",ru:"рецензент",t:"static",o:1,de:"A participant in a review who identifies defects in the work product.",dr:"Участник рецензирования, который выявляет дефекты в рабочем продукте"},
{en:"risk",ru:"риск",t:"risk",o:1,de:"A factor that could result in future negative consequences.",dr:"Фактор, который может привести к негативным последствиям в будущем, обычно выражается через вероятность и влияние."},
{en:"risk analysis",ru:"анализ рисков",t:"risk",o:1,de:"The overall process of risk identification and risk assessment.",dr:"Общий процесс определения и оценки рисков"},
{en:"risk assessment",ru:"оценка риска",t:"risk",o:1,de:"The process to examine identified risks and determine the risk level.",dr:"Процесс изучения выявленных рисков и определение их уровня"},
{en:"risk control",ru:"контроль рисков",t:"risk",o:1,de:"The overall process of risk mitigation and risk monitoring.",dr:"Общий процесс снижения и мониторинга рисков."},
{en:"risk identification",ru:"определение рисков",t:"risk",o:1,de:"The process of finding, recognizing and describing risks.",dr:"Процесс обнаружения, распознавания и описания рисков"},
{en:"risk impact",ru:"влияние риска",t:"risk",o:1,de:"The damage that will be caused if a risk becomes an actual outcome or event.",dr:"Последствия, которые проявятся в случае наступления риска"},
{en:"risk level",ru:"уровень риска",t:"risk",o:1,de:"The measure of a risk defined by risk impact and risk likelihood.",dr:"Показатель риска, определяемый влиянием риска и вероятностью риска"},
{en:"risk likelihood",ru:"вероятность риска",t:"risk",o:1,de:"The probability that a risk will become an actual outcome or event.",dr:"Вероятность того, что риск реализуется в виде фактического результата или события"},
{en:"risk management",ru:"управление рисками",t:"risk",o:1,de:"The process for handling risks.",dr:"Процесс управления рисками"},
{en:"risk mitigation",ru:"смягчение рисков",t:"risk",o:1,de:"The process through which decisions are reached and protective measures are implemented for reducing or maintaining risks to specified levels.",dr:"Процесс, в результате которого выносятся решения и принимаются защитные меры для уменьшения рисков до определенного уровня или поддержанию рисков в оговоренных рамках."},
{en:"risk monitoring",ru:"мониторинг рисков",t:"risk",o:1,de:"The activity that checks and reports the status of known risks to stakeholders.",dr:"Активность, при которой проверяется статус известных рисков и сообщается заинтересованным сторонам."},
{en:"risk-based testing",ru:"тестирование на основе рисков",t:"risk",o:1,de:"A test approach in which the management, selection, prioritization, and use of test activities and resources are based on corresponding risk types and risk levels.",dr:"Подход к тестированию, при котором управление, выбор, приоритизация и использование тестовых активностей и ресурсов основаны на соответствующих типах и уровнях рисков."},
{en:"root cause",ru:"первопричина",t:"defect",o:1,de:"A source of a defect such that if it is removed, the occurrence of the defect type is decreased or removed.",dr:"Источник дефекта, при удалении которого частота подобных дефектов сокращается, или же подобные дефекты исчезают полностью"},
{en:"root cause analysis",ru:"анализ первопричины",t:"defect",o:1,de:"An analysis technique aimed at identifying the root causes of defects.",dr:"Анализ, направленный на идентификацию первопричин дефектов. При применении мер к устранению первопричины, можно надеяться на минимизацию частоты появления дефектов определенного типа."},
{en:"safety",ru:"защищенность",t:"quality",o:1,de:"The degree to which a component or system under defined conditions can avoid endangering human life, health, property, or the environment.",dr:"Степень, с которой компонент или система при определенных условиях могут избежать угрозы жизни, здоровью, имуществу или окружающей среде человека."},
{en:"scalability",ru:"масштабируемость",t:"quality",o:1,de:"The degree to which a component or system can be adjusted for changing capacity.",dr:"Степень, с которой компонент или система могут быть настроены для изменения производительности."},
{en:"scenario-based reviewing",ru:"рецензирование на основе сценариев",t:"static",o:1,de:"A review technique in which a work product is evaluated to determine its ability to address specific scenarios.",dr:"Техника рецензирования, при которой рабочий продукт оценивается для определения его способности использовать конкретный сценарий."},
{en:"scribe",ru:"секретарь",t:"static",o:1,de:"A person who records information at a review meeting.",dr:"Лицо, записывающий информацию во время собраний по анализу и рецензированию"},
{en:"security",ru:"безопасность (защищённость)",t:"quality",o:0,de:"The degree to which a component or system defends against security attacks and provides access appropriate to types and levels of authorization.",dr:"Степень, в которой компонент или система защищается от атак и предоставляет доступ, соответствующий типам и уровням авторизации."},
{en:"sequential development model",ru:"последовательная модель разработки",t:"agile",o:1,de:"A type of software development lifecycle model in which a complete system is developed in a linear way of several discrete and successive phases with no overlap between them.",dr:"Тип модели жизненного цикла разработки программного обеспечения, в которой полная система разрабатывается линейным образом из нескольких дискретных и последовательных фаз без перекрытия между ними."},
{en:"service virtualization",ru:"виртуализация услуг",t:"auto",o:1,de:"A technique to enable the delivery of virtual services which are deployed, accessed and managed remotely.",dr:"Метод, обеспечивающий виртуальную доставку услуг, которые развернуты, доступны и управляются удаленно."},
{en:"session-based test management",ru:"управление тестированием на основе сеансов",t:"mgmt",o:1,de:"A method for measuring and managing session-based testing.",dr:"Метод измерения и управления тестированием на основе сеансов."},
{en:"session-based testing",ru:"тестирование на основе сеансов",t:"tech",o:1,de:"A test approach in which test activities are planned as test sessions.",dr:"Подход к тестированию, при котором активности тестирования планируются как тестовые сессии."},
{en:"severity",ru:"критичность",t:"defect",o:1,de:"The degree of impact that a defect has on the development or operation of a component or system.",dr:"Важность воздействия конкретного дефекта на разработку или функционирование компонента или системы."},
{en:"shift left",ru:"сдвиг влево",t:"agile",o:1,de:"A test approach to perform testing and quality assurance activities as early as possible in the software development lifecycle.",dr:"Подход к тестированию, при котором выполнение тестирования и обеспечение качества начинаются на максимально ранних этапах жизненного цикла разработки программного обеспечения"},
{en:"simulator",ru:"имитатор",t:"auto",o:1,de:"A component or system used during testing which behaves or operates like a given component or system.",dr:"Компонент или система, используемые во время тестирования, которые ведут себя или работают подобно заданным компоненту или системе."},
{en:"smoke test",ru:"тестирование минимальной работоспособности (smoke)",t:"types",o:1,de:"A test suite that covers the main functionality of a component or system to determine whether it works properly before planned testing begins.",dr:"Набор тестов, который покрывает основные функциональные возможности компонента или системы, чтобы определить, работает ли компонент или система должным образом до начала запланированного тестирования."},
{en:"software development lifecycle",ru:"жизненный цикл разработки программного обеспечения",t:"agile",o:1,de:"The activities performed at each phase in software development, and how they relate to one another logically and chronologically.",dr:"Активности, выполняемые на каждом этапе разработки программного обеспечения, и то, как они соотносятся друг с другом в логическом и хронологическом порядке."},
{en:"software lifecycle",ru:"жизненный цикл программного обеспечения",t:"agile",o:1,de:"The period of time that begins when a software product is conceived and ends when the software is no longer available for use. The software lifecycle typically includes a concept phase, requirements phase, design phase, implementation phase, test phase, installation and checkout phase, operation and maintenance phase, and sometimes, retirement phase. Note these phases may overlap or be performed iteratively.",dr:"Период времени, начинающийся с момента появления концепции программного обеспечения и заканчивающийся тогда, когда дальнейшее использование программного обеспечения невозможно. Жизненный цикл программного обеспечения обычно включает в себя следующие этапы: концепт, описание требований, дизайн, реализация, тестирование, инсталляция и наладка, эксплуатация и поддержка и, иногда, этап вывода из эксплуатации. Данные фазы могут накладываться друг на друга или проводиться итерационно."},
{en:"state transition testing",ru:"тестирование таблицы переходов",t:"tech",o:1,de:"A black-box test technique in which test conditions are state transitions or sequences of them.",dr:"Разработка тестов методом черного ящика, при котором сценарии тестирования строятся на основе модели переходов состояний."},
{en:"static analysis",ru:"статический анализ",t:"static",o:1,de:"The automated process of evaluating a component or system without executing it, based on its form, structure, content, or documentation.",dr:"Процесс оценки компонента или системы без его выполнения на основе его формы, структуры, содержимого или документации."},
{en:"static testing",ru:"статическое тестирование",t:"static",o:1,de:"A test approach that does not involve the execution of a test item.",dr:"Тестирование без запуска на исполнение тестируемого объекта"},
{en:"stub",ru:"заглушка",t:"auto",o:1,de:"A type of test double providing predefined responses.",dr:"Тип тестового заменителя, возвращающего заранее определенные ответы."},
{en:"system integration testing",ru:"системное интеграционное тестирование",t:"levels",o:1,de:"A test level that focuses on the integration of systems.",dr:"Тестирование интеграции между системами"},
{en:"system testing",ru:"системное тестирование",t:"levels",o:1,de:"A test level that focuses on verifying that a system as a whole meets specified requirements.",dr:"Уровень тестирования, который фокусируется на проверке соответствия системы в целом определенным требованиям"},
{en:"system under test",ru:"тестируемая система",t:"process",o:1,de:"A type of test object that is a system.",dr:"Тип объекта тестирования, который является системой."},
{en:"technical review",ru:"технический анализ",t:"static",o:1,de:"A formal review by technical experts that examine the quality of a work product and identify discrepancies from specifications and standards.",dr:"Тип формального рецензирования, выполняемый командой технически квалифицированных специалистов, который проверяет пригодность рабочего продукта для его предполагаемого использования и выявляет несоответствия спецификациям и стандартам."},
{en:"test",ru:"тест",t:"process",o:1,de:"A set of one or more test cases.",dr:"Набор из одного или нескольких тестовых сценариев."},
{en:"test analysis",ru:"анализ тестирования",t:"process",o:1,de:"The activity that identifies test conditions by analyzing the test basis.",dr:"Деятельность, которая направлена на определение тестовых условий путем анализа базиса тестирования"},
{en:"test approach",ru:"подход к тестированию",t:"mgmt",o:1,de:"The manner of implementing test tasks.",dr:"Способ реализации задач по тестированию."},
{en:"test automation",ru:"автоматизация тестирования",t:"auto",o:1,de:"The conversion of test activities to automated operation.",dr:"Процесс перевода тестовых активностей в автоматический режим работы."},
{en:"test automation approach",ru:"подход к автоматизации тестирования",t:"auto",o:0,de:"A test approach to automate test activities.",dr:"Подход к тестированию, направленный на автоматизацию тестовых активностей."},
{en:"test automation framework",ru:"интегрированная среда автоматизированного тестирования",t:"auto",o:1,de:"A set of test harnesses and test libraries for test automation.",dr:"Набор тестовых обвязок и тестовых библиотек для автоматизации тестирования."},
{en:"test basis",ru:"базис тестирования",t:"process",o:1,de:"The body of knowledge used as the basis for test analysis and test design.",dr:"Совокупность знаний, используемых в качестве основы для анализа тестирования и проектирования тестов."},
{en:"test case",ru:"сценарий тестирования",t:"process",o:1,de:"A set of preconditions, inputs, actions (where applicable), expected results and postconditions, developed based on test conditions.",dr:"Набор предусловий, входных данных, действий (где применимо), ожидаемых результатов и постусловий, разработанных на основе тестовых условий"},
{en:"test charter",ru:"концепция тестирования",t:"process",o:1,de:"Documentation of a test objective for a test session.",dr:"Документирование цели или задачи тестового сеанса."},
{en:"test completion",ru:"завершение тестирования",t:"process",o:1,de:"The activity that makes testware available for later use, leaves test environments in a satisfactory condition and communicates the results of testing to relevant stakeholders.",dr:"Активности, которые делают тестовое обеспечение доступными для последующего использования, оставляют тестовую среду в удовлетворительном состоянии и сообщают результаты тестирования соответствующим заинтересованным сторонам."},
{en:"test completion report",ru:"итоговый отчет о тестировании",t:"mgmt",o:1,de:"A type of test report produced at completion milestones that provides an evaluation of the corresponding test items against exit criteria.",dr:"Вид отчета о тестировании, составленный на этапах завершения, который оценивает достижение критериев выхода для элементов тестирования."},
{en:"test condition",ru:"тестовое условие",t:"process",o:1,de:"A testable aspect of a component or system that is intended to be tested.",dr:"Тестируемый аспект компонента или системы, который предполагается для тестирования"},
{en:"test control",ru:"контроль тестирования",t:"mgmt",o:1,de:"The activity that develops and applies corrective actions to get a test project on track when it deviates from what was planned.",dr:"Активность по разработке и применению корректирующих действий, чтобы привести тестовый проект в нужное русло, когда он отклоняется от запланированного"},
{en:"test cycle",ru:"цикл тестирования",t:"process",o:1,de:"An instance of the test process against a single identifiable version of the test object.",dr:"Экземпляр процесса тестирования конкретной идентифицируемой версии тестового объекта."},
{en:"test data",ru:"тестовые данные",t:"process",o:1,de:"Data needed for test execution.",dr:"Данные, необходимые для выполнения теста."},
{en:"test data preparation",ru:"подготовка тестовых данных",t:"process",o:1,de:"The activity to select data from existing databases or create, generate, manipulate and edit data for testing.",dr:"Активности по выбору данных из существующих баз данных или созданию, генерации, обработке и редактированию данных для тестирования."},
{en:"test design",ru:"проектирование теста",t:"process",o:1,de:"The activity that derives and specifies test cases from test conditions.",dr:"Активность по получению и определению тест-кейсов в соответствии с условиями тестирования."},
{en:"test environment",ru:"тестовое окружение",t:"process",o:1,de:"An environment containing hardware, instrumentation, simulators, software tools, and other support elements needed to perform a test.",dr:"Окружение, включающее аппаратное обеспечение, измерительную аппаратуру, имитаторы, программный инструментарий и прочие вспомогательные элементы, необходимые для выполнения теста."},
{en:"test estimation",ru:"оценка затрат на тестирование",t:"mgmt",o:1,de:"An approximation related to various aspects of testing.",dr:"Аппроксимация объема трудозатрат, связанная с различными аспектами тестирования."},
{en:"test execution",ru:"выполнение теста",t:"process",o:1,de:"The activity that runs a test on a component or system producing actual results.",dr:"Активность, запускающая тест компонента или системы и приводящая к фактическим результатам."},
{en:"test execution automation",ru:"автоматизация выполнения тестов",t:"auto",o:1,de:"The use of software, e.g., capture/playback tools, to control the execution of tests, the comparison of actual results to expected results, the setting up of test preconditions, and other test control and reporting functions.",dr:"Использование программного обеспечения (например, средств захвата/воспроизведения) для контроля выполнения тестов, сравнения полученных результатов с эталонными, установки предусловий тестов и других функций контроля тестирования и организации отчетов."},
{en:"test execution schedule",ru:"расписание выполнения тестов",t:"mgmt",o:1,de:"A schedule for the execution of test suites within a test cycle.",dr:"Расписание выполнения тестовых наборов в рамках цикла тестирования."},
{en:"test harness",ru:"тестовая обвязка",t:"auto",o:1,de:"A collection of drivers and test doubles needed to execute a test suite.",dr:"Набор заглушек и драйверов, необходимых для выполнения набора тестов."},
{en:"test implementation",ru:"реализация тестов",t:"process",o:0,de:"The activity that prepares the testware needed for test execution.",dr:"Деятельность по подготовке тестовых активов, необходимых для выполнения тестов."},
{en:"test item",ru:"элемент тестирования",t:"process",o:1,de:"A part of a test object used in the test process.",dr:"Часть тестового объекта, которая используется в процессе тестирования."},
{en:"test level",ru:"уровень тестирования",t:"levels",o:1,de:"A specific instantiation of a test process.",dr:"Конкретная реализация процесса тестирования."},
{en:"test log",ru:"протокол тестирования",t:"process",o:1,de:"A chronological record of relevant details about test execution.",dr:"Хронологический протокол деталей, относящихся к выполнению тестов."},
{en:"test management",ru:"управление тестированием",t:"mgmt",o:1,de:"The process of planning, scheduling, estimating, monitoring, reporting, controlling, and completing test activities.",dr:"Процесс планирования, составления плана-графика тестовых активностей, оценки, мониторинга, отчетности, контроля и завершения тестовых мероприятий."},
{en:"test manager",ru:"руководитель тестирования",t:"mgmt",o:1,de:"The person responsible for managing test activities, test resources, and evaluating the test object.",dr:"Специалист, ответственный за управление ресурсами и работами по тестированию, а также за определение качества тестируемого объекта."},
{en:"test monitoring",ru:"мониторинг тестирования",t:"mgmt",o:1,de:"The activity that checks the status of testing activities, identifies any variances from planned or expected, and reports status to stakeholders.",dr:"Деятельность, которая проверяет состояние тестовых мероприятий, выявляет любые отклонения от запланированных или ожидаемых и сообщает о состоянии заинтересованным сторонам."},
{en:"test object",ru:"объект тестирования",t:"process",o:1,de:"The work product to be tested.",dr:"Рабочий продукт, подлежащий тестированию."},
{en:"test objective",ru:"цель тестирования",t:"fund",o:1,de:"The purpose for testing.",dr:"Цель проведения  тестирования."},
{en:"test plan",ru:"план тестирования",t:"mgmt",o:0,de:"Documentation that describes test objectives, means and schedule for achieving test coordination.",dr:"Документация, описывающая цели тестирования, средства и расписание для координации тестирования."},
{en:"test planning",ru:"планирование тестирования",t:"mgmt",o:1,de:"The activity of establishing or updating a test plan.",dr:"Работа по составлению и поддержанию актуальности плана тестирования."},
{en:"test policy",ru:"политика тестирования",t:"mgmt",o:1,de:"High-level documentation describing the principles, approach and major objectives of the organization regarding testing.",dr:"Документация высокого уровня, описывающая принципы, подход и основные цели организации в отношении тестирования."},
{en:"test procedure",ru:"процедура тестирования",t:"process",o:1,de:"A sequence of test cases in execution order and any associated actions that may be required to set up the initial preconditions and any wrap-up activities after execution.",dr:"Последовательность тестовых случаев в порядке их выполнения или другие активности , которые могут потребоваться для настройки предварительных условий и завершающих активностей после выполнения тестирования."},
{en:"test process",ru:"процесс тестирования",t:"fund",o:0,de:"A set of test activities performed to achieve a test objective.",dr:"Набор тестовых активностей, выполняемых для достижения цели тестирования."},
{en:"test progress",ru:"прогресс тестирования",t:"mgmt",o:1,de:"The progress of testing against a baseline.",dr:"Прогресс тестирования по сравнению с предыдущим состоянием."},
{en:"test progress report",ru:"отчет о ходе тестирования",t:"mgmt",o:1,de:"A type of periodic test report that includes the progress of test activities against a baseline, risks, and alternatives requiring a decision.",dr:"Тип периодического отчета о тестировании, который включает информацию о ходе активностей тестирования в сравнении с исходными планами, риски и альтернативы, требующие принятия решения."},
{en:"test pyramid",ru:"пирамида тестирования",t:"auto",o:1,de:"A graphical model representing the relationship of the amount of testing per level, with more at the bottom than at the top.",dr:"Графическая модель, представляющая соотношение количества тестов на каждом уровне тестирования, причем внизу их больше, чем вверху."},
{en:"test report",ru:"отчет о тестировании",t:"mgmt",o:1,de:"Documentation summarizing testing and test results.",dr:"Документация, обобщающая деятельность и результаты тестирования."},
{en:"test reporting",ru:"отчётность по тестированию",t:"mgmt",o:0,de:"The activity that consolidates test monitoring information and evaluates whether test objectives have been reached to inform stakeholders.",dr:"Деятельность по консолидации данных мониторинга и оценке достижения целей тестирования для информирования заинтересованных сторон."},
{en:"test result",ru:"результат теста",t:"process",o:0,de:"The status of the execution of a test.",dr:"Статус выполнения теста."},
{en:"test run",ru:"прогон теста",t:"process",o:1,de:"The execution of a test suite on a specific version of the test object.",dr:"Выполнение набора тестов для конкретной версии объекта тестирования."},
{en:"test schedule",ru:"график тестирования",t:"mgmt",o:1,de:"A list of activities, tasks, and milestones of the test process, their intended start and finish dates and interdependencies.",dr:"Список активностей, задач и вех в процессе тестирования, определяющий даты их начала и завершения, а так же их взаимозависимости."},
{en:"test scope",ru:"объем тестирования",t:"mgmt",o:1,de:"A description of the test object and its features to be tested.",dr:"Описание объекта тестирования и его функционала, подлежащего тестированию."},
{en:"test script",ru:"автоматизированный сценарий тестирования",t:"process",o:1,de:"A sequence of instructions for the execution of a test.",dr:"Последовательность инструкций для выполнения автоматизированного теста."},
{en:"test session",ru:"сессия тестирования",t:"process",o:1,de:"An uninterrupted period of time spent in executing tests.",dr:"Непрерывный промежуток времени, во время которого выполняются тесты."},
{en:"test specification",ru:"спецификация теста",t:"process",o:1,de:"The complete documentation of the test design, test cases, and test scripts for a specific test item.",dr:"Полная документация, содержащая описания проектирования тестов, тестовых наборов и процедур тестирования для конкретного тестируемого элемента."},
{en:"test strategy",ru:"стратегия тестирования",t:"mgmt",o:1,de:"A description of how to perform testing to reach test objectives under given circumstances.",dr:"Описание того, как выполнять тестирование для достижения целей тестирования в заданных условиях"},
{en:"test suite",ru:"набор тестов",t:"process",o:1,de:"A set of test scripts or test procedures to be executed in a specific test run.",dr:"Набор сценариев тестирования или тестовых процедур, выполняемых в определенном тестовом прогоне."},
{en:"test technique",ru:"метод тестирования",t:"tech",o:1,de:"A procedure used to define test conditions, design test cases, and specify test data.",dr:"Процедура, используемая для определения условий тестирования, проектирования сценариев тестирования и формирования тестовых данных."},
{en:"test type",ru:"тип тестирования",t:"types",o:1,de:"A group of test activities based on specific test objectives aimed at specific characteristics of a component or system.",dr:"Группа активностей тестирования, направленных на тестирование характеристик компонента или системы с определенной целью."},
{en:"test-driven development",ru:"разработка на основе тестов",t:"agile",o:1,de:"A software development technique in which the test cases are developed, automated and then the software is developed incrementally to pass those test cases.",dr:"Методика разработки программного обеспечения, в котором сценарии тестирования разрабатываются, автоматизируются, а затем программное обеспечение разрабатывается небольшими приращениями функциональности с целью успешного прохождения соответствующих тестовых сценариев"},
{en:"test-first approach",ru:"подход опережающего проектирования тестов",t:"agile",o:1,de:"An approach to software development in which the test cases are designed and implemented before the associated component or system is developed.",dr:"Подход к разработке программного обеспечения, при котором сценарии тестирования разрабатываются и реализуются до разработки соответствующего компонента или системы."},
{en:"testability",ru:"тестируемость",t:"quality",o:1,de:"The degree to which test conditions can be established for a component or system, and tests can be performed to determine whether those test conditions have been met.",dr:"Степень эффективности и действенности, с которой тесты могут быть разработаны и выполнены для компонента или системы."},
{en:"tester",ru:"тестировщик",t:"fund",o:1,de:"A person who performs testing.",dr:"Специалист, проводящий тестирование"},
{en:"testing",ru:"тестирование",t:"fund",o:1,de:"The process within the software development lifecycle that evaluates the quality of a component or system and related work products.",dr:"Процесс в рамках жизненного цикла разработки программного обеспечения, который оценивает качество компонента или системы, а также связанных с ними рабочих продуктов."},
{en:"testing quadrants",ru:"квадранты тестирования",t:"agile",o:1,de:"A classification model of test types/test levels in four quadrants, relating them to two dimensions of test objectives: supporting the product team versus critiquing the product, and technology-facing versus business-facing.",dr:"Модель классификации типов тестирования/уровней тестирования по четырем квадрантам, соотносящая их с двумя аспектами целей тестирования: поддержка команды разработчиков в сравнении с критикой продукта и ориентация на технологии в сравнении с ориентацией на бизнес."},
{en:"testware",ru:"тестовое обеспечение",t:"process",o:1,de:"Work products produced during the test process for use in planning, designing, executing, evaluating and reporting on testing.",dr:"Рабочие продукты, созданные в процессе тестирования для использования в планировании, проектировании, выполнении, оценке и отчетности по тестированию."},
{en:"traceability",ru:"трассируемость",t:"mgmt",o:1,de:"The ability to establish explicit relationships between related work products or items within work products.",dr:"Способность устанавливать явные взаимосвязи между рабочими продуктами или элементами рабочих продуктов."},
{en:"unit test framework",ru:"фреймворк модульного тестирования",t:"auto",o:0,de:"A tool that provides an environment for testing a unit in isolation.",dr:"Инструмент, предоставляющий среду для тестирования модуля изолированно."},
{en:"usability",ru:"практичность",t:"quality",o:1,de:"The degree to which a component or system can be used by specified users to achieve specified goals in a specified context of use.",dr:"Степень, с которой компонент или система могут использоваться указанными пользователями для достижения конкретных целей в контексте использования."},
{en:"usability lab",ru:"лаборатория практичности",t:"quality",o:1,de:"A test facility in which unintrusive observation of participant reactions and responses to software takes place.",dr:"Тестовая площадка, на которой проводится ненавязчивое наблюдение за реакциями и ответами участников, взаимодействующих с программным обеспечением"},
{en:"usability testing",ru:"тестирование практичности",t:"types",o:1,de:"Testing to evaluate the degree to which the system can be used by specified users with effectiveness, efficiency and satisfaction in a specified context of use.",dr:"Тестирование для оценки степени того, насколько результативно и эффективно может использоваться система определенными пользователями в заданном контексте использования."},
{en:"user acceptance testing",ru:"пользовательское приёмочное тестирование",t:"levels",o:1,de:"A type of acceptance testing performed to determine if intended users accept the system.",dr:"Тип приемочного тестирования, выполняемого для определения того, принимают ли предполагаемые пользователи систему."},
{en:"user experience",ru:"пользовательский опыт",t:"quality",o:1,de:"A person's perceptions and responses resulting from the use or anticipated use of a software product.",dr:"Восприятие и реакции человека, вызванные использованием или предполагаемым использованием программного продукта."},
{en:"user interface",ru:"пользовательский интерфейс",t:"process",o:1,de:"All components of a system that provide information and controls for the user to accomplish specific tasks with the system.",dr:"Все компоненты системы, предоставляющие пользователю информацию и элементы управления для выполнения определенных задач в системе."},
{en:"user story",ru:"пользовательская история",t:"agile",o:0,de:"A short narrative describing a need from a user's perspective together with the expected benefit when this need is satisfied.",dr:"Краткое описание потребности с точки зрения пользователя вместе с ожидаемой выгодой при её удовлетворении."},
{en:"V-model",ru:"V-модель",t:"agile",o:1,de:"A sequential software development lifecycle model describing a one-for-one relationship between major phases of software development from business requirements specification to delivery, and corresponding test levels from acceptance testing to component testing.",dr:"Последовательная модель жизненного цикла разработки, описывающая взаимно-однозначное соответствие между основными этапами разработки программного обеспечения от спецификации бизнес-требований до поставки и соответствующими уровнями тестирования от приемочного тестирования до тестирования компонентов."},
{en:"validation",ru:"валидация",t:"fund",o:1,de:"Confirmation by examination that a work product matches a stakeholder's needs.",dr:"Подтверждение путем экспертизы того, что рабочий продукт соответствует потребностям заинтересованной стороны."},
{en:"verification",ru:"верификация",t:"fund",o:1,de:"The process of confirming that a work product fulfills its specification.",dr:"Процесс подтверждения того, что продукт соответствует установленной спецификации."},
{en:"walkthrough",ru:"разбор",t:"static",o:1,de:"A type of formal review in which an author leads members of the review through a work product and the members ask questions and make comments.",dr:"Тип рецензирования, в котором автор знакомит участников рецензирования с рабочим продуктом, а участники задают вопросы и комментируют возможные проблемы."},
{en:"white-box test technique",ru:"тестирование методом белого ящика",t:"tech",o:1,de:"A test technique based on the internal structure of a component or system.",dr:"Методика тестирования, основанная на внутренней структуре компонента или системы."},
{en:"white-box testing",ru:"тестирование белого ящика",t:"types",o:0,de:"A test approach based on the internal structure of a component or system.",dr:"Подход к тестированию, основанный на внутренней структуре компонента или системы."}
];